1	/**
2	 * Bridge between the track Zustand store and live WebAudio instrument instances.
3	 * Subscribes to track additions/removals, creates/disposes SynthInstrument
4	 * and DrumKit instances, and forwards store parameter changes to audio engines.
5	 *
6	 * Follows the same pattern as EffectsBridge and RoutingBridge.
7	 */
8	
9	import { useDawStore } from "@state/store";
10	import { useSynthStore } from "@state/synth/synth-store";
11	import type { SynthParameterMap } from "./synth/synth-types";
12	import {
13	  createSynthInstrument,
14	  type SynthInstrument,
15	} from "./synth/synth-instrument";
16	import { subscribeModRoutes } from "./synth/modulation-bridge";
17	import { createDrumKit } from "./drum-machine/drum-kit";
18	import type { DrumKit } from "./drum-machine/drum-types";
19	import {
20	  DRUM_INSTRUMENTS,
21	  type DrumInstrumentId,
22	} from "./drum-machine/drum-types";
23	import type { MixerEngine } from "./mixer/types";
24	import type { TrackModel } from "@state/track/types";
25	
26	export type TrackAudioBridge = {
27	  getInstrument(trackId: string): SynthInstrument | undefined;
28	  getDrumKit(trackId: string): DrumKit | undefined;
29	  dispose(): void;
30	};
31	
32	/**
33	 * Subscribe a SynthInstrument to param changes from useSynthStore.
34	 * Sends current params immediately, then diffs future changes.
35	 */
36	function subscribeSynthParams(
37	  trackId: string,
38	  instrument: SynthInstrument,
39	): () => void {
40	  // Send current params
41	  const current = useSynthStore.getState().getParams(trackId);
42	  for (const key of Object.keys(current) as (keyof SynthParameterMap)[]) {
43	    instrument.setParam(key, current[key]);
44	  }
45	
46	  let prevRef = useSynthStore.getState().synths[trackId];
47	
48	  return useSynthStore.subscribe((state) => {
49	    const synth = state.synths[trackId];
50	    if (!synth || synth === prevRef) return;
51	
52	    const prevParams = prevRef?.params;
53	    prevRef = synth;
54	
55	    if (!prevParams) return;
56	
57	    for (const key of Object.keys(
58	      synth.params,
59	    ) as (keyof SynthParameterMap)[]) {
60	      if (synth.params[key] !== prevParams[key]) {
61	        instrument.setParam(key, synth.params[key]);
62	      }
63	    }
64	  });
65	}
66	
67	/** Create silent placeholder AudioBuffers for each drum instrument. */
68	function createPlaceholderSamples(
69	  ctx: AudioContext,
70	): Map<DrumInstrumentId, AudioBuffer> {
71	  const samples = new Map<DrumInstrumentId, AudioBuffer>();
72	  for (const inst of DRUM_INSTRUMENTS) {
73	    samples.set(inst.id, ctx.createBuffer(1, 1, ctx.sampleRate));
74	  }
75	  return samples;
76	}
77	
78	export function createTrackAudioBridge(
79	  ctx: AudioContext,
80	  mixer: MixerEngine,
81	): TrackAudioBridge {
82	  const instruments = new Map<string, SynthInstrument>();
83	  const drumKits = new Map<string, DrumKit>();
84	  const trackCleanups = new Map<string, () => void>();
85	  // Generation counter to detect stale async instrument resolutions
86	  const trackGeneration = new Map<string, number>();
87	  let disposed = false;
88	
89	  function addInstrumentTrack(trackId: string): void {
90	    const gen = (trackGeneration.get(trackId) ?? 0) + 1;
91	    trackGeneration.set(trackId, gen);
92	    mixer.getOrCreateStrip(trackId);
93	    useSynthStore.getState().initSynth(trackId);
94	
95	    void createSynthInstrument(ctx).then((instrument) => {
96	      if (trackGeneration.get(trackId) !== gen || disposed) {
97	        instrument.dispose();
98	        return;
99	      }
100	
101	      instruments.set(trackId, instrument);
102	      instrument.connectToMixer(mixer, trackId);
103	
104	      const unsubParams = subscribeSynthParams(trackId, instrument);
105	      const unsubMod = subscribeModRoutes(trackId, instrument);
106	
107	      trackCleanups.set(trackId, () => {
108	        unsubParams();
109	        unsubMod();
110	        instrument.disconnectFromMixer(mixer, trackId);
111	        instrument.dispose();
112	        instruments.delete(trackId);
113	      });
114	    });
115	  }
116	
117	  function addDrumTrack(trackId: string): void {
118	    const samples = createPlaceholderSamples(ctx);
119	    const kit = createDrumKit(ctx, samples);
120	    drumKits.set(trackId, kit);
121	    kit.connectToMixer(mixer, trackId);
122	
123	    trackCleanups.set(trackId, () => {
124	      kit.disconnectFromMixer(mixer, trackId);
125	      kit.dispose();
126	      drumKits.delete(trackId);
127	    });
128	  }
129	
130	  function addAudioTrack(trackId: string): void {
131	    mixer.getOrCreateStrip(trackId);
132	    trackCleanups.set(trackId, () => {
133	      mixer.removeStrip(trackId);
134	    });
135	  }
136	
137	  function handleTrackAdded(track: TrackModel): void {
138	    switch (track.type) {
139	      case "instrument":
140	        addInstrumentTrack(track.id);
141	        break;
142	      case "drum":
143	        addDrumTrack(track.id);
144	        break;
145	      case "audio":
146	        addAudioTrack(track.id);
147	        break;
148	    }
149	  }
150	
151	  function handleTrackRemoved(trackId: string): void {
152	    // Bump generation so in-flight async instrument creation is discarded
153	    trackGeneration.set(trackId, (trackGeneration.get(trackId) ?? 0) + 1);
154	    trackCleanups.get(trackId)?.();
155	    trackCleanups.delete(trackId);
156	    mixer.removeStrip(trackId);
157	    useSynthStore.getState().removeSynth(trackId);
158	  }
159	
160	  // Sync existing tracks on creation
161	  let prevTrackMap = new Map<string, TrackModel>();
162	  const initialTracks = useDawStore.getState().tracks;
163	  for (const track of initialTracks) {
164	    handleTrackAdded(track);
165	    prevTrackMap.set(track.id, track);
166	  }
167	
168	  // Subscribe to future track changes
169	  const unsubStore = useDawStore.subscribe((state) => {
170	    const current = new Map(state.tracks.map((t) => [t.id, t]));
171	
172	    // Added
173	    for (const [id, track] of current) {
174	      if (!prevTrackMap.has(id)) {
175	        handleTrackAdded(track);
176	      }
177	    }
178	
179	    // Removed
180	    for (const id of prevTrackMap.keys()) {
181	      if (!current.has(id)) {
182	        handleTrackRemoved(id);
183	      }
184	    }
185	
186	    prevTrackMap = current;
187	  });
188	
189	  return {
190	    getInstrument(trackId: string): SynthInstrument | undefined {
191	      return instruments.get(trackId);
192	    },
193	
194	    getDrumKit(trackId: string): DrumKit | undefined {
195	      return drumKits.get(trackId);
196	    },
197	
198	    dispose(): void {
199	      disposed = true;
200	      unsubStore();
201	
202	      for (const cleanup of trackCleanups.values()) {
203	        cleanup();
204	      }
205	      trackCleanups.clear();
206	      trackGeneration.clear();
207	    },
208	  };
209	}
