1	/**
2	 * Provider that creates the TrackAudioBridge and ClipScheduler.
3	 * Bridges track store changes to live WebAudio instrument/kit instances.
4	 * Must be rendered inside EffectsBridgeProvider (needs mixer access).
5	 */
6	
7	import { createContext, useContext, useEffect, useRef, useState } from "react";
8	import { useAudioEngine } from "@audio/use-audio-engine";
9	import { useEffectsBridgeContext } from "@audio/effects/EffectsBridgeProvider";
10	import { useTransport } from "@audio/use-transport";
11	import { useMediaPool } from "@audio/media-pool/use-media-pool";
12	import { useDawStore } from "@state/store";
13	import { isAudioClip } from "@state/track/types";
14	import {
15	  createTrackAudioBridge,
16	  type TrackAudioBridge,
17	} from "./track-audio-bridge";
18	import {
19	  createClipScheduler,
20	  type ClipScheduler,
21	} from "./mixer/clip-scheduler";
22	
23	const Ctx = createContext<TrackAudioBridge | null>(null);
24	
25	export function TrackAudioBridgeProvider({
26	  children,
27	}: {
28	  children: React.ReactNode;
29	}): React.JSX.Element {
30	  const engine = useAudioEngine();
31	  const { mixer } = useEffectsBridgeContext();
32	  const transport = useTransport();
33	  const pool = useMediaPool();
34	
35	  const [value] = useState<{
36	    bridge: TrackAudioBridge;
37	    clipScheduler: ClipScheduler;
38	  }>(() => ({
39	    bridge: createTrackAudioBridge(engine.ctx, mixer),
40	    clipScheduler: createClipScheduler(engine.ctx),
41	  }));
42	
43	  // Maintain a sync buffer cache for clip scheduling
44	  const bufferCacheRef = useRef(new Map<string, AudioBuffer>());
45	  const inFlightRef = useRef(new Set<string>());
46	
47	  // Prefetch clip buffers when clips change; evict stale entries
48	  useEffect(() => {
49	    function syncBuffers(clips: Record<string, unknown>): void {
50	      const activeSourceIds = new Set<string>();
51	      for (const clip of Object.values(clips)) {
52	        if (isAudioClip(clip)) {
53	          activeSourceIds.add(clip.sourceId);
54	          if (
55	            !bufferCacheRef.current.has(clip.sourceId) &&
56	            !inFlightRef.current.has(clip.sourceId)
57	          ) {
58	            inFlightRef.current.add(clip.sourceId);
59	            void pool
60	              .getAudioBuffer(clip.sourceId)
61	              .then((buf) => {
62	                if (buf) bufferCacheRef.current.set(clip.sourceId, buf);
63	              })
64	              .catch((err: unknown) => {
65	                console.warn("Failed to prefetch buffer:", clip.sourceId, err);
66	              })
67	              .finally(() => {
68	                inFlightRef.current.delete(clip.sourceId);
69	              });
70	          }
71	        }
72	      }
73	      // Evict buffers for removed clips
74	      for (const sourceId of bufferCacheRef.current.keys()) {
75	        if (!activeSourceIds.has(sourceId)) {
76	          bufferCacheRef.current.delete(sourceId);
77	        }
78	      }
79	    }
80	
81	    syncBuffers(useDawStore.getState().clips);
82	    const unsub = useDawStore.subscribe((state) => {
83	      syncBuffers(state.clips);
84	    });
85	    return unsub;
86	  }, [pool]);
87	
88	  // Wire clip scheduler into transport's onAdvance callback
89	  useEffect(() => {
90	    transport.setOnAdvanceCallback(
91	      (windowStart: number, windowEnd: number, timeOffset: number) => {
92	        const state = useDawStore.getState();
93	        const audioClips = Object.values(state.clips).filter(isAudioClip);
94	        // Filter to non-muted tracks
95	        const hasSolo = state.tracks.some((t) => t.solo);
96	        const activeTrackIds = new Set(
97	          state.tracks
98	            .filter((t) => {
99	              if (t.muted) return false;
100	              if (hasSolo && !t.solo && !t.soloIsolate) return false;
101	              return true;
102	            })
103	            .map((t) => t.id),
104	        );
105	        const activeClips = audioClips.filter((c) =>
106	          activeTrackIds.has(c.trackId),
107	        );
108	
109	        // Schedule clips per track (each goes to its own mixer strip)
110	        const byTrack = new Map<string, typeof activeClips>();
111	        for (const clip of activeClips) {
112	          const arr = byTrack.get(clip.trackId) ?? [];
113	          arr.push(clip);
114	          byTrack.set(clip.trackId, arr);
115	        }
116	
117	        for (const [trackId, clips] of byTrack) {
118	          const strip = mixer.getStrip(trackId);
119	          if (!strip) continue;
120	          value.clipScheduler.scheduleClips(
121	            clips,
122	            windowStart,
123	            windowEnd,
124	            timeOffset,
125	            (sourceId) => bufferCacheRef.current.get(sourceId),
126	            strip.inputGain,
127	          );
128	        }
129	      },
130	    );
131	    return () => {
132	      transport.setOnAdvanceCallback(null);
133	    };
134	  }, [transport, mixer, value.clipScheduler]);
135	
136	  // Stop all clip playback when transport stops
137	  useEffect(() => {
138	    return useDawStore.subscribe((state, prev) => {
139	      if (
140	        prev.transportState !== "stopped" &&
141	        state.transportState === "stopped"
142	      ) {
143	        value.clipScheduler.stopAll();
144	      }
145	    });
146	  }, [value.clipScheduler]);
147	
148	  // Guard against StrictMode double-mount (same pattern as EffectsBridgeProvider)
149	  const mountedRef = useRef(true);
150	  useEffect(() => {
151	    mountedRef.current = true;
152	    return () => {
153	      mountedRef.current = false;
154	      setTimeout(() => {
155	        if (!mountedRef.current) {
156	          value.clipScheduler.stopAll();
157	          value.bridge.dispose();
158	        }
159	      }, 0);
160	    };
161	  }, [value]);
162	
163	  return <Ctx.Provider value={value.bridge}>{children}</Ctx.Provider>;
164	}
165	
166	export function useTrackAudioBridge(): TrackAudioBridge {
167	  const bridge = useContext(Ctx);
168	  if (bridge === null) {
169	    throw new Error(
170	      "useTrackAudioBridge must be used within TrackAudioBridgeProvider",
171	    );
172	  }
173	  return bridge;
174	}
