1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { useDawStore } from "@state/store";
3	import { useAutomationStore } from "@state/automation";
4	import { isAudioClip, type AudioClipModel } from "@state/track/types";
5	import { AddClipCommand } from "@state/track/track-commands";
6	import { sharedUndoManager } from "@state/undo";
7	import { useMediaPool } from "@audio/media-pool/use-media-pool";
8	import { useAudioEngine } from "@audio/use-audio-engine";
9	import {
10	  renderArrangement,
11	  type ArrangementViewState,
12	} from "./arrangement-renderer";
13	import { useArrangementInteractions } from "./use-arrangement-interactions";
14	import { xToSeconds, snapToGrid, type GridSnap } from "./hit-test";
15	import { RULER_HEIGHT } from "./constants";
16	import styles from "./ArrangementPanel.module.css";
17	
18	const DEFAULT_VIEW: ArrangementViewState = {
19	  scrollX: 0,
20	  scrollY: 0,
21	  pixelsPerSecond: 100,
22	  trackHeight: 64,
23	  headerWidth: 160,
24	};
25	
26	const MIN_PPS = 10;
27	const MAX_PPS = 500;
28	const ZOOM_FACTOR = 1.1;
29	
30	type ArrangementPanelProps = {
31	  onOpenPianoRoll?: (clipId: string) => void;
32	};
33	
34	export function ArrangementPanel({
35	  onOpenPianoRoll,
36	}: ArrangementPanelProps): React.JSX.Element {
37	  const canvasRef = useRef<HTMLCanvasElement>(null);
38	  const rafRef = useRef(0);
39	  const [view, setView] = useState(DEFAULT_VIEW);
40	  const [gridSnap] = useState<GridSnap>("1/4");
41	  const interactions = useArrangementInteractions(
42	    view,
43	    gridSnap,
44	    onOpenPianoRoll,
45	  );
46	  const bpmForDrop = useDawStore((s) => s.bpm);
47	
48	  const handleDragOver = useCallback(
49	    (e: React.DragEvent<HTMLCanvasElement>): void => {
50	      if (!e.dataTransfer.types.includes("application/x-media-pool-source"))
51	        return;
52	
53	      const rect = e.currentTarget.getBoundingClientRect();
54	      const y = e.clientY - rect.top;
55	      const trackIndex = Math.floor(
56	        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
57	      );
58	      const state = useDawStore.getState();
59	      const track = trackIndex >= 0 ? state.tracks[trackIndex] : undefined;
60	      if (track !== undefined && track.type === "audio") {
61	        e.preventDefault();
62	        e.dataTransfer.dropEffect = "copy";
63	      }
64	    },
65	    [view],
66	  );
67	
68	  const handleDrop = useCallback(
69	    (e: React.DragEvent<HTMLCanvasElement>): void => {
70	      const raw = e.dataTransfer.getData("application/x-media-pool-source");
71	      if (!raw) return;
72	      e.preventDefault();
73	
74	      let parsed: unknown;
75	      try {
76	        parsed = JSON.parse(raw);
77	      } catch {
78	        return;
79	      }
80	      const data = parsed as Record<string, unknown>;
81	      if (
82	        typeof data.sourceId !== "string" ||
83	        typeof data.name !== "string" ||
84	        typeof data.durationSeconds !== "number"
85	      )
86	        return;
87	
88	      const rect = e.currentTarget.getBoundingClientRect();
89	      const x = e.clientX - rect.left;
90	      const y = e.clientY - rect.top;
91	
92	      const state = useDawStore.getState();
93	      const trackIndex = Math.floor(
94	        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
95	      );
96	      if (trackIndex < 0) return;
97	      const track = state.tracks[trackIndex];
98	      if (track === undefined || track.type !== "audio") return;
99	
100	      const dropTime = snapToGrid(
101	        Math.max(0, xToSeconds(x, view)),
102	        bpmForDrop,
103	        gridSnap,
104	      );
105	
106	      const clip: AudioClipModel = {
107	        type: "audio",
108	        id: "clip-" + crypto.randomUUID(),
109	        trackId: track.id,
110	        sourceId: data.sourceId,
111	        startTime: dropTime,
112	        sourceOffset: 0,
113	        duration: data.durationSeconds,
114	        gain: 1,
115	        fadeIn: 0,
116	        fadeOut: 0,
117	        name: data.name,
118	      };
119	
120	      const cmd = new AddClipCommand(clip);
121	      cmd.execute();
122	      sharedUndoManager.push(cmd);
123	    },
124	    [view, gridSnap, bpmForDrop],
125	  );
126	
127	  const tracks = useDawStore((s) => s.tracks);
128	  const clips = useDawStore((s) => s.clips);
129	  const selectedClipIds = useDawStore((s) => s.selectedClipIds);
130	  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
131	  const bpm = useDawStore((s) => s.bpm);
132	  const transportState = useDawStore((s) => s.transportState);
133	  const automationLanes = useAutomationStore((s) => s.lanes);
134	  const pool = useMediaPool();
135	  const engine = useAudioEngine();
136	
137	  // Fetch and slice waveform peaks per audio clip
138	  const SAMPLES_PER_PEAK = 256;
139	  const [clipPeaks, setClipPeaks] = useState<
140	    Record<string, { peaks: Float32Array; length: number }>
141	  >({});
142	
143	  useEffect(() => {
144	    let cancelled = false;
145	    const sampleRate = engine.ctx.sampleRate;
146	
147	    async function fetchPeaks(): Promise<void> {
148	      const result: Record<string, { peaks: Float32Array; length: number }> =
149	        {};
150	      for (const clip of Object.values(clips)) {
151	        if (!isAudioClip(clip)) continue;
152	        const wp = await pool.getPeaks(clip.sourceId, SAMPLES_PER_PEAK);
153	        if (cancelled) return;
154	        if (!wp || wp.length === 0) continue;
155	
156	        // Slice peaks to match clip's sourceOffset and duration
157	        const startPeak = Math.floor(
158	          (clip.sourceOffset * sampleRate) / wp.samplesPerPeak,
159	        );
160	        const peakCount = Math.ceil(
161	          (clip.duration * sampleRate) / wp.samplesPerPeak,
162	        );
163	        const endPeak = Math.min(startPeak + peakCount, wp.length);
164	        const sliceLen = Math.max(0, endPeak - startPeak);
165	
166	        result[clip.id] = {
167	          peaks: wp.peaks.slice(startPeak * 2, endPeak * 2),
168	          length: sliceLen,
169	        };
170	      }
171	      if (!cancelled) setClipPeaks(result);
172	    }
173	
174	    void fetchPeaks();
175	    return () => {
176	      cancelled = true;
177	    };
178	  }, [clips, pool, engine.ctx.sampleRate]);
179	
180	  // Render loop
181	  const render = useCallback((): void => {
182	    const canvas = canvasRef.current;
183	    if (canvas === null) return;
184	    const ctx = canvas.getContext("2d");
185	    if (ctx === null) return;
186	
187	    const rect = canvas.getBoundingClientRect();
188	    renderArrangement({
189	      ctx,
190	      width: rect.width,
191	      height: rect.height,
192	      view,
193	      tracks,
194	      clips,
195	      selectedClipIds,
196	      cursorSeconds,
197	      bpm,
198	      automationLanes,
199	      clipPeaks,
200	    });
201	  }, [
202	    view,
203	    tracks,
204	    clips,
205	    selectedClipIds,
206	    cursorSeconds,
207	    bpm,
208	    automationLanes,
209	    clipPeaks,
210	  ]);
211	
212	  // Schedule re-render when state changes or during playback
213	  useEffect(() => {
214	    const tick = (): void => {
215	      render();
216	      if (transportState === "playing") {
217	        rafRef.current = requestAnimationFrame(tick);
218	      }
219	    };
220	
221	    rafRef.current = requestAnimationFrame(tick);
222	    return (): void => {
223	      cancelAnimationFrame(rafRef.current);
224	    };
225	  }, [render, transportState]);
226	
227	  // Handle canvas sizing with ResizeObserver
228	  useEffect(() => {
229	    const canvas = canvasRef.current;
230	    if (canvas === null) return;
231	    const parent = canvas.parentElement;
232	    if (parent === null) return;
233	
234	    const resizeCanvas = (): void => {
235	      const dpr = window.devicePixelRatio;
236	      const rect = parent.getBoundingClientRect();
237	      canvas.width = rect.width * dpr;
238	      canvas.height = rect.height * dpr;
239	      canvas.style.width = `${String(rect.width)}px`;
240	      canvas.style.height = `${String(rect.height)}px`;
241	
242	      const ctx = canvas.getContext("2d");
243	      if (ctx !== null) {
244	        ctx.scale(dpr, dpr);
245	      }
246	    };
247	
248	    if (typeof ResizeObserver === "undefined") return;
249	
250	    const observer = new ResizeObserver(resizeCanvas);
251	    observer.observe(parent);
252	    resizeCanvas();
253	
254	    return (): void => {
255	      observer.disconnect();
256	    };
257	  }, []);
258	
259	  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
260	  const handleWheel = useCallback(
261	    (e: React.WheelEvent<HTMLCanvasElement>): void => {
262	      e.preventDefault();
263	
264	      if (e.ctrlKey || e.metaKey) {
265	        // Zoom
266	        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
267	        setView((prev) => ({
268	          ...prev,
269	          pixelsPerSecond: Math.min(
270	            MAX_PPS,
271	            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
272	          ),
273	        }));
274	      } else if (e.shiftKey) {
275	        // Horizontal scroll
276	        setView((prev) => ({
277	          ...prev,
278	          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
279	        }));
280	      } else {
281	        // Vertical scroll
282	        setView((prev) => ({
283	          ...prev,
284	          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
285	          scrollY: Math.max(0, prev.scrollY + e.deltaY),
286	        }));
287	      }
288	    },
289	    [],
290	  );
291	
292	  return (
293	    <section data-testid="arrangement-panel" className={styles["container"]}>
294	      <span id="arrangement-keys" hidden>
295	        Scroll: mouse wheel. Horizontal scroll: Shift + wheel. Zoom: Ctrl/Cmd +
296	        wheel. Double-click to create clip. Click to select. Drag to move clips.
297	      </span>
298	      <canvas
299	        ref={canvasRef}
300	        role="application"
301	        aria-label="Arrangement timeline"
302	        aria-describedby="arrangement-keys"
303	        className={styles["canvas"]}
304	        style={{ cursor: interactions.cursor }}
305	        onWheel={handleWheel}
306	        onPointerDown={interactions.onPointerDown}
307	        onPointerMove={interactions.onPointerMove}
308	        onPointerUp={interactions.onPointerUp}
309	        onDoubleClick={interactions.onDoubleClick}
310	        onDragOver={handleDragOver}
311	        onDrop={handleDrop}
312	      />
313	    </section>
314	  );
315	}
