8	import { useTransportCursor } from "@ui/hooks/useTransportCursor";
9	import type { TempoMap } from "@audio/tempo-map";
10	
11	type CursorDisplayProps = {
12	  transportSAB: SharedArrayBuffer | null;
13	  tempoMap: TempoMap | null;
14	};
15	
16	function formatBBT(bar: number, beat: number, tick: number): string {
17	  const b = String(bar).padStart(3, "0");
18	  const bt = String(beat).padStart(2, "0");
19	  const t = String(tick).padStart(3, "0");
20	  return `${b}.${bt}.${t}`;
21	}
22	
23	export function CursorDisplay({
24	  transportSAB,
25	  tempoMap,
26	}: CursorDisplayProps): React.JSX.Element {
27	  const cursorRef = useTransportCursor(transportSAB);
28	  const spanRef = useRef<HTMLSpanElement>(null);
29	
30	  useEffect(() => {
31	    if (tempoMap === null) return;
32	
33	    let rafId = 0;
34	
35	    function update(): void {
36	      if (spanRef.current !== null && tempoMap !== null) {
37	        const bbt = tempoMap.secondsToBBT(cursorRef.current);
38	        spanRef.current.textContent = formatBBT(bbt.bar, bbt.beat, bbt.tick);
39	      }
40	      rafId = requestAnimationFrame(update);
41	    }
42	
43	    rafId = requestAnimationFrame(update);
44	    return () => {
45	      cancelAnimationFrame(rafId);
46	    };
47	  }, [tempoMap, cursorRef]);
48	
49	  return (
50	    <span
51	      ref={spanRef}
52	      data-testid="cursor-display"
53	      aria-label="Cursor position"
54	      style={{
55	        fontFamily: "var(--font-mono)",
56	        fontSize: "var(--text-sm)",
57	        color: "var(--color-green)",
58	        minWidth: "80px",
59	        textAlign: "center",
60	      }}
61	    >
62	      001.01.000
63	    </span>
64	  );
65	}
