23	export function EffectsBridgeProvider({
24	  children,
25	}: {
26	  children: React.ReactNode;
27	}): React.JSX.Element {
28	  const engine = useAudioEngine();
29	  const transport = useTransport();
30	
31	  const [value] = useState<EffectsBridgeContext>(() => {
32	    const registry = createDefaultRegistry();
33	    const mixer = createMixerEngine(engine.ctx);
