40	    transport.setParamResolver(createParamResolver(value.mixer, value.bridge));
41	  }, [value, transport]);
42	
43	  // Guard against StrictMode double-mount: only dispose on true unmount.
44	  // useState initializers are called once and cached in React 18/19,
45	  // so the deferred check is sufficient — no duplicate instances are created.
46	  const mountedRef = useRef(true);
