1	/**
2	 * Controller hook that bridges the transport audio layer to the Zustand store.
3	 * Creates and manages TransportClock, LookAheadScheduler, Metronome,
4	 * and AutomationScheduler.
5	 *
6	 * useTransportInit() — initialization (used only by TransportProvider)
7	 * useTransport()     — context consumer (used by all other components)
8	 */
9	
10	import { useCallback, useContext, useEffect, useRef } from "react";
11	import { useAudioEngine } from "./use-audio-engine";
12	import { createTransportClock, type TransportClock } from "./transport-clock";
13	import {
14	  createLookAheadScheduler,
15	  type LookAheadScheduler,
16	} from "./look-ahead-scheduler";
17	import { createMetronome, type Metronome } from "./metronome";
18	import {
19	  createAutomationScheduler,
20	  type AutomationScheduler,
21	  type ParamResolver,
22	} from "./automation/automation-scheduler";
23	import {
24	  createSharedBuffers,
25	  type SharedArrayBufferLayout,
26	} from "./shared-buffer-layout";
27	import { useDawStore } from "@state/index";
28	import { useAutomationStore } from "@state/automation";
29	import { TransportCtx } from "./transport-ctx";
30	
31	export type OnAdvanceCallback = (
32	  windowStart: number,
33	  windowEnd: number,
34	  timeOffset: number,
35	) => void;
36	
37	export type UseTransportReturn = {
38	  play(): void;
39	  pause(): void;
40	  stop(): void;
41	  seek(seconds: number): void;
42	  setBpm(bpm: number): void;
43	  setMetronomeEnabled(on: boolean): void;
44	  getTransportSAB(): SharedArrayBuffer | null;
45	  getClock(): TransportClock | null;
46	  /** Set the param resolver for automation playback (call from mixer provider) */
47	  setParamResolver(resolver: ParamResolver): void;
48	  /** Set an additional onAdvance callback for clip scheduling (call from bridge provider) */
49	  setOnAdvanceCallback(cb: OnAdvanceCallback | null): void;
50	};
51	
52	/**
53	 * Initializes the transport audio stack. Used only by TransportProvider.
54	 */
55	export function useTransportInit(): UseTransportReturn {
56	  const engine = useAudioEngine();
57	  const clockRef = useRef<TransportClock | null>(null);
58	  const schedulerRef = useRef<LookAheadScheduler | null>(null);
59	  const metronomeRef = useRef<Metronome | null>(null);
60	  const autoSchedulerRef = useRef<AutomationScheduler | null>(null);
61	  const paramResolverRef = useRef<ParamResolver>(() => undefined);
62	  const onAdvanceCallbackRef = useRef<OnAdvanceCallback | null>(null);
63	  const sabRef = useRef<SharedArrayBufferLayout | null>(null);
64	
65	  const storePlay = useDawStore((s) => s.play);
66	  const storePause = useDawStore((s) => s.pause);
67	  const storeStop = useDawStore((s) => s.stop);
68	  const storeSetBpm = useDawStore((s) => s.setBpm);
69	  const storeSetCursor = useDawStore((s) => s.setCursor);
70	  const bpm = useDawStore((s) => s.bpm);
71	  const loopEnabled = useDawStore((s) => s.loopEnabled);
72	  const loopStart = useDawStore((s) => s.loopStart);
73	  const loopEnd = useDawStore((s) => s.loopEnd);
74	
75	  // Sync loop region from store to clock
76	  useEffect(() => {
77	    clockRef.current?.setLoop({
78	      enabled: loopEnabled,
79	      start: loopStart,
80	      end: loopEnd,
81	    });
82	  }, [loopEnabled, loopStart, loopEnd]);
83	
84	  // Initialize on mount
85	  useEffect(() => {
86	    const sab = createSharedBuffers();
87	    sabRef.current = sab;
88	
89	    const clock = createTransportClock(engine.ctx, sab.transport, bpm);
90	    clockRef.current = clock;
91	
92	    const met = createMetronome(engine.ctx);
93	    metronomeRef.current = met;
94	
95	    // Automation scheduler: resolver is ref-based so it can be set later by mixer
96	    const autoSched = createAutomationScheduler((lane) =>
97	      paramResolverRef.current(lane),
98	    );
99	    autoSchedulerRef.current = autoSched;
100	
101	    const scheduler = createLookAheadScheduler(
102	      engine.ctx,
103	      clock,
104	      undefined,
105	      (beatTime: number, beatNumber: number) => {
106	        const beatsPerBar = clock.getTempoMap().timeSignature.numerator;
107	        const isDownbeat = beatNumber % beatsPerBar === 0;
108	        met.scheduleTick(beatTime, isDownbeat);
109	      },
110	      (windowStart: number, windowEnd: number, timeOffset: number) => {
111	        // Gather all armed lanes from the automation store
112	        const allLanes = useAutomationStore.getState().lanes;
113	        const lanes = Object.values(allLanes).flat();
114	        autoSched.scheduleWindow(lanes, windowStart, windowEnd, timeOffset);
115	        // Clip scheduling (set by TrackAudioBridgeProvider)
116	        onAdvanceCallbackRef.current?.(windowStart, windowEnd, timeOffset);
117	      },
118	    );
119	    schedulerRef.current = scheduler;
120	
121	    return () => {
122	      scheduler.stop();
123	      autoSched.cancelAll();
124	      met.dispose();
125	      clock.dispose();
126	      clockRef.current = null;
127	      schedulerRef.current = null;
128	      metronomeRef.current = null;
129	      autoSchedulerRef.current = null;
130	      sabRef.current = null;
131	    };
132	    // eslint-disable-next-line react-hooks/exhaustive-deps -- init once
133	  }, [engine]);
134	
135	  const play = useCallback((): void => {
136	    const clock = clockRef.current;
137	    const scheduler = schedulerRef.current;
138	    if (clock === null || scheduler === null) return;
139	    if (clock.state === "playing") return;
140	
141	    clock.play();
142	    scheduler.start();
