1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { useTransport } from "@audio/use-transport";
3	import { useDawStore } from "@state/index";
4	import type { TrackType } from "@state/track/types";
5	import { BpmInput } from "./BpmInput";
6	import { CursorDisplay } from "./CursorDisplay";
7	import { BounceDialog } from "@ui/session/BounceDialog";
8	import styles from "./TransportBar.module.css";
9	
10	const TRACK_PRESETS: {
11	  label: string;
12	  type: TrackType;
13	  color: string;
14	  namePrefix: string;
15	}[] = [
16	  {
17	    label: "Audio Track",
18	    type: "audio",
19	    color: "#4A90D9",
20	    namePrefix: "Audio",
21	  },
22	  {
23	    label: "Instrument Track",
24	    type: "instrument",
25	    color: "#D94A90",
26	    namePrefix: "Synth",
27	  },
28	  { label: "Drum Track", type: "drum", color: "#FF6B35", namePrefix: "808" },
29	];
30	
31	export function TransportBar(): React.JSX.Element {
32	  const transport = useTransport();
33	  const transportState = useDawStore((s) => s.transportState);
34	  const bpm = useDawStore((s) => s.bpm);
35	  const loopEnabled = useDawStore((s) => s.loopEnabled);
36	  const setLoop = useDawStore((s) => s.setLoop);
37	  const addTrack = useDawStore((s) => s.addTrack);
38	  const setSelectedTrackIds = useDawStore((s) => s.setSelectedTrackIds);
39	  const [metronomeOn, setMetronomeOn] = useState(false);
40	  const [addMenuOpen, setAddMenuOpen] = useState(false);
41	  const [bounceOpen, setBounceOpen] = useState(false);
42	  const addMenuRef = useRef<HTMLDivElement>(null);
43	
44	  const handleLoopToggle = useCallback((): void => {
45	    setLoop(!loopEnabled);
46	  }, [loopEnabled, setLoop]);
47	
48	  const handleMetronomeToggle = useCallback((): void => {
49	    const next = !metronomeOn;
50	    setMetronomeOn(next);
51	    transport.setMetronomeEnabled(next);
52	  }, [metronomeOn, transport]);
53	
54	  const handleBpmChange = useCallback(
55	    (newBpm: number): void => {
56	      transport.setBpm(newBpm);
57	    },
58	    [transport],
59	  );
60	
61	  const handleAddTrack = useCallback(
62	    (type: TrackType, color: string, namePrefix: string): void => {
63	      const existing = useDawStore
64	        .getState()
65	        .tracks.filter((t) => t.type === type);
66	      const maxNum = existing.reduce((max, t) => {
67	        if (t.name.startsWith(namePrefix + " ")) {
68	          const num = parseInt(t.name.slice(namePrefix.length + 1), 10);
69	          if (!Number.isNaN(num)) return Math.max(max, num);
70	        }
71	        return max;
72	      }, 0);
73	      const id = crypto.randomUUID();
74	      addTrack({
75	        id,
76	        name: `${namePrefix} ${String(maxNum + 1)}`,
77	        type,
78	        color,
79	        muted: false,
80	        solo: false,
81	        armed: false,
82	        soloIsolate: false,
83	        volume: 1,
84	        pan: 0,
85	        clipIds: [],
86	      });
87	      setSelectedTrackIds([id]);
88	      setAddMenuOpen(false);
89	    },
90	    [addTrack, setSelectedTrackIds],
91	  );
92	
93	  // Close menu on outside click or Escape key
94	  useEffect(() => {
95	    if (!addMenuOpen) return;
96	    const handleClick = (e: MouseEvent): void => {
