1	/**
2	 * 16-step pattern sequencer for the TR-808 drum machine.
3	 * Manages pattern state (A/B), step toggles, accent, flam.
4	 * Emits DrumTrigger events on scheduleStep() calls from the scheduler.
5	 *
6	 * R-STA-06: Synchronized to transport via external scheduler callback.
7	 */
8	
9	import {
10	  createEmptyPattern,
11	  DRUM_INSTRUMENTS,
12	  type DrumInstrumentId,
13	  type DrumStep,
14	  type DrumPattern,
15	  type DrumTrigger,
16	} from "./drum-types";
17	
18	const NORMAL_VELOCITY = 0.8;
19	const ACCENT_VELOCITY = 1.0;
20	const STEPS_PER_PATTERN = 16;
21	
22	export type StepSequencer = {
23	  /** Schedule all triggers for a given step at the given audio time */
24	  scheduleStep(stepIndex: number, time: number): void;
25	  /** Toggle an instrument on/off at a step */
26	  toggleStep(instrumentId: DrumInstrumentId, stepIndex: number): void;
27	  /** Set accent for a step */
28	  setAccent(stepIndex: number, accent: boolean): void;
29	  /** Set flam timing for a step (ms) */
30	  setFlam(stepIndex: number, flamMs: number): void;
31	  /** Switch active pattern */
32	  switchPattern(name: string): void;
33	  /** Get active pattern name */
34	  getActivePatternName(): string;
35	  /** Get a snapshot of the current pattern */
36	  getPattern(): DrumPattern;
37	  /** Clear all steps in the active pattern */
38	  clearPattern(): void;
39	};
40	
41	export function createStepSequencer(
42	  onTrigger: (trigger: DrumTrigger) => void,
43	): StepSequencer {
44	  const patterns = new Map<string, DrumStep[]>();
45	  let activePatternName = "A";
46	
47	  // Initialize A and B
48	  patterns.set("A", createSteps());
49	  patterns.set("B", createSteps());
50	
51	  function createSteps(): DrumStep[] {
52	    return createEmptyPattern().steps.map((s) => ({
53	      ...s,
54	      triggers: { ...s.triggers },
55	    }));
56	  }
57	
58	  function getActiveSteps(): DrumStep[] {
59	    let steps = patterns.get(activePatternName);
60	    if (!steps) {
61	      steps = createSteps();
62	      patterns.set(activePatternName, steps);
63	    }
64	    return steps;
65	  }
66	
67	  const seq: StepSequencer = {
68	    scheduleStep(stepIndex: number, time: number): void {
69	      const idx = stepIndex % STEPS_PER_PATTERN;
70	      const steps = getActiveSteps();
71	      const step = steps[idx];
72	      if (!step) return;
73	      const velocity = step.accent ? ACCENT_VELOCITY : NORMAL_VELOCITY;
74	
75	      for (const inst of DRUM_INSTRUMENTS) {
76	        if (step.triggers[inst.id]) {
77	          onTrigger({
78	            instrumentId: inst.id,
79	            time,
80	            velocity,
81	            flamMs: step.flamMs > 0 ? step.flamMs : undefined,
82	          });
83	        }
84	      }
85	    },
86	
87	    toggleStep(instrumentId: DrumInstrumentId, stepIndex: number): void {
88	      const steps = getActiveSteps();
89	      const idx = stepIndex % STEPS_PER_PATTERN;
90	      const step = steps[idx];
91	      if (!step) return;
92	      const newTriggers = { ...step.triggers };
93	      newTriggers[instrumentId] = !newTriggers[instrumentId];
94	      steps[idx] = { ...step, triggers: newTriggers };
95	    },
96	
97	    setAccent(stepIndex: number, accent: boolean): void {
98	      const steps = getActiveSteps();
99	      const idx = stepIndex % STEPS_PER_PATTERN;
100	      const step = steps[idx];
101	      if (!step) return;
102	      steps[idx] = { ...step, accent };
103	    },
104	
105	    setFlam(stepIndex: number, flamMs: number): void {
106	      const steps = getActiveSteps();
107	      const idx = stepIndex % STEPS_PER_PATTERN;
108	      const step = steps[idx];
109	      if (!step) return;
110	      steps[idx] = { ...step, flamMs };
111	    },
112	
113	    switchPattern(name: string): void {
114	      if (!patterns.has(name)) {
115	        patterns.set(name, createSteps());
116	      }
117	      activePatternName = name;
118	    },
119	
120	    getActivePatternName(): string {
121	      return activePatternName;
122	    },
123	
124	    getPattern(): DrumPattern {
125	      const steps = getActiveSteps();
126	      return {
127	        name: activePatternName,
128	        steps: steps.map((s) => ({ ...s, triggers: { ...s.triggers } })),
129	      };
130	    },
131	
132	    clearPattern(): void {
133	      patterns.set(activePatternName, createSteps());
134	    },
135	  };
136	
137	  return seq;
138	}
139

