// Transport sync: advance step indicator when playing
const rafRef = useRef(0);
useEffect(() => {
  if (transportState !== "playing") return;

  const clock = transport.getClock();
  if (!clock) return;

  const stepsPerBeat = 4; // 16th notes
  let lastStep = -1;

  const tick = (): void => {
    const cursor = clock.getCursorSeconds();
    const stepDuration = 60 / (bpm * stepsPerBeat);
    const step = Math.floor(cursor / stepDuration) % pattern.steps.length;
    if (step !== lastStep) {
      lastStep = step;
      setLiveStep(step);
    }
    rafRef.current = requestAnimationFrame(tick);
  };
  rafRef.current = requestAnimationFrame(tick);

  return () => {
    cancelAnimationFrame(rafRef.current);
  };
}, [transportState, transport, bpm, pattern.steps.length]);

// Audio scheduling: schedule drum steps within look-ahead window
useEffect(() => {
  if (transportState !== "playing") return;
  const clock = transport.getClock();
  if (!clock) return;

  const stepsPerBeat = 4;
  const stepDuration = 60 / (bpm * stepsPerBeat);
  let nextStepTime = 0;
  let nextStepIndex = 0;
  const lookAheadSec = 0.1;
  const intervalMs = 25;

  // Sync to current position
  const cursor = clock.getCursorSeconds();
  const totalSteps = cursor / stepDuration;
  const wholeStep = Math.floor(totalSteps + 1e-9);
  const remainder = totalSteps - wholeStep;
  if (remainder < 1e-6) {
    nextStepIndex = wholeStep % pattern.steps.length;
    nextStepTime = cursor;
  } else {
    nextStepIndex = (wholeStep + 1) % pattern.steps.length;
    nextStepTime = (wholeStep + 1) * stepDuration;
  }

  const timerId = setInterval(() => {
    if (clock.state !== "playing") return;
    const now = clock.getCursorSeconds();
    const windowEnd = now + lookAheadSec;
    // timeOffset: convert arrangement time to AudioContext time
    // This is approximate; for sample-accuracy we'd need ctx.currentTime
    while (nextStepTime < windowEnd) {
      const audioTime = nextStepTime - now + (performance.now() / 1000);
      // Use scheduleStep which fires onTrigger for each active instrument
      seq.scheduleStep(nextStepIndex, Math.max(0, nextStepTime - now));
      nextStepIndex = (nextStepIndex + 1) % pattern.steps.length;
      nextStepTime += stepDuration;
    }
  }, intervalMs);

  return () => {
    clearInterval(timerId);
  };
}, [transportState, transport, bpm, seq, pattern.steps.length]);

