    expect(inst).toBeDefined();
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion, @typescript-eslint/unbound-method
    expect(inst!.connectToMixer).toHaveBeenCalledWith(mixer, "t1");
  });

