    useDawStore.getState().addTrack(track);

    bridge = createTrackAudioBridge(ctx, mixer);

    await vi.waitFor(() => {
      expect(bridge.getInstrument("t1")).toBeDefined();
    });
  });

  it("dispose cleans up all instruments and kits", async () => {
    bridge = createTrackAudioBridge(ctx, mixer);

