    const canvas = canvasRef.current;
    if (canvas === null) return;
    const ctx = canvas.getContext("2d");
    if (ctx === null) return;

    const rect = canvas.getBoundingClientRect();
    renderArrangement({
      ctx,
      width: rect.width,
      height: rect.height,
      view,
      tracks,
      clips,
      selectedClipIds,
      cursorSeconds,
      bpm,
      automationLanes,
      clipPeaks,
    });
  }, [
    view,
    tracks,
    clips,
    selectedClipIds,
    cursorSeconds,
    bpm,
    automationLanes,
    clipPeaks,
  ]);

