  // During playback, read cursor from SAB (updated by audio thread) instead of
  // stale Zustand store value to keep the playback cursor moving smoothly.
  useEffect(() => {
    const tick = (): void => {
      if (transportState === "playing") {
        const canvas = canvasRef.current;
        if (canvas !== null) {
          const ctx = canvas.getContext("2d");
          if (ctx !== null) {
            const rect = canvas.getBoundingClientRect();
            renderArrangement({
              ctx,
              width: rect.width,
              height: rect.height,
              view,
              tracks,
              clips,
              selectedClipIds,
              cursorSeconds: sabCursorRef.current,
              bpm,
              automationLanes,
              clipPeaks,
            });
          }
        }
        rafRef.current = requestAnimationFrame(tick);
      } else {
        render();
      }
    };

    rafRef.current = requestAnimationFrame(tick);
    return (): void => {
      cancelAnimationFrame(rafRef.current);
    };
  }, [render, transportState, sabCursorRef, view, tracks, clips, selectedClipIds, bpm, automationLanes, clipPeaks]);

