    tracks: s.tracks,
    clips: s.clips,
    selectedClipIds: s.selectedClipIds,
    cursorSeconds: cursor,
    bpm: s.bpm,
    automationLanes: s.automationLanes,
    clipPeaks: s.clipPeaks,
  });
}, [sabCursorRef]);

// Re-render on state changes (non-playback)
useEffect(() => {
  renderOnce();
}, [renderOnce, view, tracks, clips, selectedClipIds, cursorSeconds, bpm, automationLanes, clipPeaks]);

